async (params, browser) => {
  // Search Etsy
  await browser.open(`https://www.etsy.com/search?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('.v2-listing-card, a.listing-link, li[data-listing-id]', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract product results
  const search_results = await browser.evaluate(`const results = []; const cards = document.querySelectorAll('.v2-listing-card'); if (cards.length === 0) { const altCards = document.querySelectorAll('li[data-listing-id], [data-palette-listing-id]'); for (let i = 0; i < Math.min(altCards.length, 15); i++) { const el = altCards[i]; const titleEl = el.querySelector('h2, h3, a[title]'); const priceEl = el.querySelector('span.currency-value, [data-currency-value]'); const currencyEl = el.querySelector('span.currency-symbol'); const linkEl = el.querySelector('a.listing-link, a[href*="/listing/"]'); const imgEl = el.querySelector('img'); const ratingEl = el.querySelector('[aria-label*="star"], [aria-label*="rating"]'); const shopEl = el.querySelector('p a[href*="/shop/"], [aria-label*="shop"]'); const reviewCountEl = el.querySelector('[aria-label*="review"], [aria-label*="sale"]'); const freeShippingEl = el.querySelector('[aria-label*="shipping"], [data-free-shipping]'); if (titleEl || linkEl) { results.push({ title: titleEl ? (titleEl.getAttribute('title') || titleEl.textContent.trim()) : '', price: (currencyEl ? currencyEl.textContent.trim() : '') + (priceEl ? priceEl.textContent.trim() : ''), url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '', rating: ratingEl ? ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', shop_name: shopEl ? shopEl.textContent.trim() : '', free_shipping: !!freeShippingEl }); } } } else { for (let i = 0; i < Math.min(cards.length, 15); i++) { const el = cards[i]; const titleEl = el.querySelector('h2.v2-listing-card__title, h3.v2-listing-card__title, h2, h3, a[title]'); const priceEl = el.querySelector('span.currency-value, [data-currency-value]'); const currencyEl = el.querySelector('span.currency-symbol'); const linkEl = el.querySelector('a.listing-link, a[href*="/listing/"]'); const imgEl = el.querySelector('img'); const ratingEl = el.querySelector('[aria-label*="star"], [aria-label*="rating"]'); const shopEl = el.querySelector('p a[href*="/shop/"], [aria-label*="shop"]'); const reviewCountEl = el.querySelector('[aria-label*="review"], [aria-label*="sale"]'); const freeShippingEl = el.querySelector('[aria-label*="shipping"], [data-free-shipping]'); results.push({ title: titleEl ? (titleEl.getAttribute('title') || titleEl.textContent.trim()) : '', price: (currencyEl ? currencyEl.textContent.trim() : '') + (priceEl ? priceEl.textContent.trim() : ''), url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '', rating: ratingEl ? ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', shop_name: shopEl ? shopEl.textContent.trim() : '', free_shipping: !!freeShippingEl }); } } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
